// ─────────────────────────────────────────────────────────────────────────────

function tsvToGeoJSON(tsv) {
  const lines = tsv.trim().split(/\r?\n/);
  if (lines.length < 2) return { type: "FeatureCollection", features: [] };
  const headers = lines[0].split("\t").map(h => h.trim());
  const features = [];

  for (let i = 1; i < lines.length; i++) {
    if (!lines[i].trim()) continue;
    const cols = lines[i].split("\t");
    if (cols.length < headers.length) continue;

    const obj = {};
    headers.forEach((h, j) => {
      obj[h] = cols[j] ? cols[j].trim() : "";
    });

    const lat = parseFloat(obj["latitude"]);
    const lon = parseFloat(obj["longitude"]);
    if (isNaN(lat) || isNaN(lon)) continue;

    features.push({
      type: "Feature",
      properties: {
        name: obj["speciesname"] || "",
        latitude: lat,
        longitude: lon,
        foundBy: obj["recordedby"] || "",
        dateFound: obj["datefound"] || "",
        determinedBy: obj["determinedby"] || "",
        lifeStage: obj["lifestage"] || "",
        sex: obj["sex"] || "",
        notes: obj["notes"] || "",
        rights: obj["rights"] || "",
        rightsHolder: obj["rightsholder"] || "",
        sourceLink: obj["sourcelink"] || "",
        gbif_link: obj["gbif_link"] || "",
        locality: obj["locality"] || "",
      },
      geometry: { type: "Point", coordinates: [lon, lat] },
    });
  }

  return { type: "FeatureCollection", features };
}

// Parse all three datasets
const allSpeciesData  = tsvToGeoJSON(tsvText);
const communisData    = tsvToGeoJSON(tsvTextCommunis);
const alopexData      = tsvToGeoJSON(tsvTextAlopex);

// Build a Set of exact lat/lon keys present in either subspecies dataset.
// Any species-wide point matching one of these will be suppressed.
function coordKey(lat, lon) {
  return `${parseFloat(lat).toFixed(6)}_${parseFloat(lon).toFixed(6)}`;
}

const subspeciesKeys = new Set();
[...communisData.features, ...alopexData.features].forEach(f => {
  subspeciesKeys.add(coordKey(f.properties.latitude, f.properties.longitude));
});

// Species-wide layer: drop points that duplicate a subspecies coordinate
const speciesData = {
  type: "FeatureCollection",
  features: allSpeciesData.features.filter(f =>
    !subspeciesKeys.has(coordKey(f.properties.latitude, f.properties.longitude))
  ),
};

// ─── Map placeholder injection (unchanged from original) ─────────────────────
function isVisible(el) {
  return el && !!(el.offsetWidth || el.offsetHeight || el.getClientRects().length);
}

const allPlaceholders = document.querySelectorAll(".map-placeholder");
let target = null;
allPlaceholders.forEach((el) => {
  if (isVisible(el)) target = el;
});

const mapEl = document.getElementById("map");
if (target && mapEl) {
  target.appendChild(mapEl);
  console.log("🗺️ Moved map into:", target.parentElement.className);
}

// Land mask — not used for the species range (that now comes from pasted GeoJSON).
// If you have a land polygon to clip the sympatry overlay, paste it here.
const landMask = null;

// ─── Create map ───────────────────────────────────────────────────────────────
const map = L.map("map").setView([39, -98], 4);
L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
  maxZoom: 14,
  attribution: "&copy; OpenStreetMap contributors",
}).addTo(map);

// ─── Popup builder (unchanged from original) ─────────────────────────────────
function buildPopup(p) {
  const popupParts = [
    `<b>${p.name}</b>`,
    `<b>Coordinates:</b> ${p.latitude.toFixed(4)}, ${p.longitude.toFixed(4)}`
  ];

  if (p.locality && p.locality.trim() !== "")
    popupParts.push(`<b>Locality:</b> ${p.locality}`);

  popupParts.push(
    `<b>Recorded By:</b> ${p.foundBy || "Unknown"}`,
    `<b>Date Found:</b> ${p.dateFound || "Unknown"}`,
    `<b>Determined By:</b> ${p.determinedBy || "Unknown"}`,
    `<b>Life Stage:</b> ${p.lifeStage || "Unknown"}`,
    `<b>Sex:</b> ${p.sex || "Unknown"}`,
    `<b>Notes:</b> ${p.notes || "None"}`
  );

  if (p.rights) popupParts.push(`<b>Rights:</b> ${p.rights}`);
  if (p.rightsHolder) popupParts.push(`<b>Rights Holder:</b> ${p.rightsHolder}`);

  if (p.gbif_link) {
    popupParts.push(
      `<b>Source:</b> <a href="${p.gbif_link}" target="_blank" rel="noopener noreferrer">View GBIF Record</a>`
    );
    if (p.sourceLink) {
      const link = p.sourceLink.trim();
      if (/^https?:\/\//i.test(link)) {
        popupParts.push(
          `<b>Discover Life Link:</b> <a href="${link}" target="_blank" rel="noopener noreferrer">View Discover Life Record</a>`
        );
      } else {
        popupParts.push(`<b>Discover Life Link:</b> ${link}`);
      }
    }
  } else if (p.sourceLink) {
    const link = p.sourceLink.trim();
    const isURL = /^https?:\/\//i.test(link);
    const isDOI = /^10\.\d{4,9}\/[-._;()/:A-Z0-9]+$/i.test(link);
    if (isURL) {
      popupParts.push(
        `<b>Source:</b> <a href="${link}" target="_blank" rel="noopener noreferrer">View Record</a>`
      );
    } else if (isDOI) {
      popupParts.push(
        `<b>Source:</b> <a href="https://doi.org/${link}" target="_blank" rel="noopener noreferrer">${link}</a>`
      );
    } else {
      popupParts.push(`<b>Source:</b> ${link}`);
    }
  }

  return popupParts.join("<br>");
}

// ─── Point layer helper ───────────────────────────────────────────────────────
// Maps zoom level to circle radius (px) — tweak values here to taste.
function zoomToRadius(zoom) {
  if (zoom >= 12) return 7;
  if (zoom >= 10) return 6;
  if (zoom >= 8)  return 5;
  if (zoom >= 6)  return 4;
  if (zoom >= 5)  return 3;
  return 2;
}

function addPointLayer(geojson, color) {
  const layer = L.geoJSON(geojson, {
    pointToLayer: (feature, latlng) => {
      const marker = L.circleMarker(latlng, {
        radius: zoomToRadius(map.getZoom()),
        color: color,
        fillColor: color,
        fillOpacity: 0.9,
      });
      marker.bindPopup(buildPopup(feature.properties));
      return marker;
    },
  }).addTo(map);

  // Resize all markers in this layer on zoom
  map.on("zoomend", () => {
    const r = zoomToRadius(map.getZoom());
    layer.eachLayer(m => m.setRadius(r));
  });

  return layer;
}

// ─── Range polygon helper ─────────────────────────────────────────────────────
function buildRangePolygon(geojson, bufferKm) {
  if (!geojson.features.length) return null;
  let hull = turf.convex(geojson, { maxEdge: 5 });
  if (!hull) hull = turf.convex(geojson);
  if (!hull) return null;

  let buffered = null;
  try {
    buffered = turf.buffer(hull, bufferKm, { units: "kilometers" });
  } catch {
    buffered = hull;
  }

  let clipped = null;
  try {
    clipped = landMask ? turf.intersect(buffered, landMask) : buffered;
  } catch {
    clipped = buffered;
  }

  let smoothed = null;
  try {
    smoothed = turf.simplify(clipped || buffered, { tolerance: 0.1, highQuality: true });
  } catch {
    smoothed = clipped || buffered;
  }

  return smoothed;
}

// ─── Draw range polygons FIRST (so points render on top) ─────────────────────

// All records combined (used for bounds-fitting below)
const allRecords = {
  type: "FeatureCollection",
  features: [
    ...allSpeciesData.features,
    ...communisData.features,
    ...alopexData.features,
  ],
};

