// ─────────────────────────────────────────────────────────────────────────────

if (speciesRangeGeoJSON) {
  L.geoJSON(speciesRangeGeoJSON, {
    style: {
      color: "#3366ff",
      weight: 2,
      fillColor: "#6699ff",
      fillOpacity: 0.25,
      smoothFactor: 1,
    },
    interactive: false,
  }).addTo(map);
} else {
  console.warn("No species range GeoJSON found — paste the notebook output into speciesRangeGeoJSON.");
}

// Sympatry polygon: intersection of the two subspecies convex hulls
// Only drawn when BOTH subspecies have data and their ranges overlap.
const communisRange = buildRangePolygon(communisData, 100);
const alopexRange   = buildRangePolygon(alopexData,   100);

if (communisRange && alopexRange) {
  let overlapPoly = null;
  try {
    overlapPoly = turf.intersect(communisRange, alopexRange);
  } catch (e) {
    console.warn("Sympatry polygon error:", e);
  }

}

// ─── Draw point layers (on top of polygons) ───────────────────────────────────
// Draw in order: communis → alopex → species (species on very top)
const communisLayer = addPointLayer(communisData, "#2563eb");
const alopexLayer   = addPointLayer(alopexData,   "#ff6600");
const speciesLayer  = addPointLayer(speciesData,  "#2ab492"); 

// ─── Fit bounds to all valid points ──────────────────────────────────────────
if (allRecords.features.length > 0) {
  const bounds = allRecords.features.map(f => [
    f.geometry.coordinates[1],
    f.geometry.coordinates[0],
  ]);
  map.fitBounds(bounds, { padding: [10, 10] });
} else {
  console.warn("⚠️ No valid points found in any TSV block.");
}

// ─── Resize handlers (unchanged from original) ───────────────────────────────
window.addEventListener("resize", () => {
  setTimeout(() => map.invalidateSize(), 500);
});
setTimeout(() => map.invalidateSize(), 700);

window.addEventListener("resize", () => {
  setTimeout(() => {
    const allPlaceholders = document.querySelectorAll(".map-placeholder");
    const mapEl = document.getElementById("map");
    let target = null;
    allPlaceholders.forEach((el) => {
      if (el.offsetParent !== null) target = el;
    });
    if (target && mapEl && target !== mapEl.parentElement) {
      target.appendChild(mapEl);
      console.log("🔄 Moved map to:", target.parentElement.className);
      if (typeof map !== "undefined" && map.invalidateSize) map.invalidateSize();
    }
  }, 600);
});